svg.script:
//
(function() {
  var svg    = document.getElementById('root');
  var ns     = 'http://www.w3.org/2000/svg';
  var isDark = true;

  /* ── Toggles ── */
  document.getElementById('dark-toggle').addEventListener('click', function() {
    setMode(!svg.classList.contains('dark'));
  });
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });

  /* ── Data ── */
  var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
  var xs   = [126.9, 221.8, 316.7, 411.6, 506.4, 601.3, 696.2, 791.1];
  var colW = 36; /* half-width of hit zone = half bar width */

  var series = [
    { label:'Cyan',    color:'#22D3EE', vals:[38,42,46,50,55,60,66,72] },
    { label:'Violet',  color:'#A78BFA', vals:[32,35,38,41,45,50,56,62] },
    { label:'Emerald', color:'#10B981', vals:[18,20,21,23,25,27,31,35] },
    { label:'Amber',   color:'#FBB724', vals:[11,12,13,14,15,17,19,22] },
    { label:'Slate',   color:'#94A3B8', vals:[10,11,12,13,14,16,17,19] },
  ];

  var totals = xs.map(function(_,qi){
    return series.reduce(function(s,sr){ return s + sr.vals[qi]; }, 0);
  });

  var hitLayer = document.getElementById('hit-layer');
  var tipLayer = document.getElementById('tip-layer');
  var allTips  = {};

  function el(tag, attrs) {
    var e = document.createElementNS(ns, tag);
    Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
    return e;
  }

  /* ── Build hit zones + column tooltips ── */
  xs.forEach(function(x, qi) {
    var bw  = 168;
    var bh  = 146;
    var hw  = bw / 2;
    var bCx = x;
    var bCy = 195;

    if (bCx - hw < 72)  bCx = 72  + hw;
    if (bCx + hw > 846) bCx = 846 - hw;

    var tipG = el('g', { 'class':'tip', id:'tip_'+qi });
    tipLayer.appendChild(tipG);
    allTips[qi] = tipG;

    tipG.appendChild(el('rect', { x:bCx-hw, y:bCy-12, width:bw, height:bh+12, rx:10,
      'class':'bub-bg', filter:'url(#tipshadow)' }));
    tipG.appendChild(el('rect', { x:bCx-hw, y:bCy-12, width:bw, height:bh+12, rx:10,
      'class':'bub-bdr' }));

    var qLbl = el('text', { x:bCx, y:bCy+5, 'text-anchor':'middle',
      'dominant-baseline':'central', 'class':'bub-lbl' });
    qLbl.textContent = quarters[qi];
    tipG.appendChild(qLbl);

    tipG.appendChild(el('line', { x1:bCx-hw+8, y1:bCy+15, x2:bCx+hw-8, y2:bCy+15,
      'class':'tip-div' }));

    series.forEach(function(s, si) {
      var rowY = bCy + 28 + si * 18;
      tipG.appendChild(el('circle', { cx:bCx-hw+14, cy:rowY, r:4, fill:s.color }));
      var sLbl = el('text', { x:bCx-hw+24, y:rowY, 'dominant-baseline':'central',
        'class':'bub-lbl' });
      sLbl.textContent = s.label;
      tipG.appendChild(sLbl);
      var sVal = el('text', { x:bCx+hw-8, y:rowY, 'text-anchor':'end',
        'dominant-baseline':'central', 'class':'bub-val', 'font-size':'11' });
      sVal.textContent = '$'+s.vals[qi]+'M';
      tipG.appendChild(sVal);
    });

    tipG.appendChild(el('line', { x1:bCx-hw+8, y1:bCy+118, x2:bCx+hw-8, y2:bCy+118,
      'class':'tip-div' }));
    var totLbl = el('text', { x:bCx-hw+8, y:bCy+130, 'dominant-baseline':'central',
      'class':'bub-lbl' });
    totLbl.textContent = 'Total';
    tipG.appendChild(totLbl);
    var totVal = el('text', { x:bCx+hw-8, y:bCy+130, 'text-anchor':'end',
      'dominant-baseline':'central', 'class':'bub-val' });
    totVal.textContent = '$'+totals[qi]+'M';
    tipG.appendChild(totVal);

    /* Hit zone centered on bar */
    var hit = el('rect', { x:x-colW, y:100, width:colW*2, height:408,
      fill:'transparent', cursor:'crosshair' });
    hitLayer.appendChild(hit);

    var ch = document.getElementById('ch'+qi);
    hit.addEventListener('mouseenter', function() {
      allTips[qi].style.opacity = '1';
      if (ch) ch.style.opacity = '1';
    });
    hit.addEventListener('mouseleave', function() {
      allTips[qi].style.opacity = '';
      if (ch) ch.style.opacity = '';
    });
  });

  /* ── setMode ── */
  function setMode(wantDark) {
    var currently = svg.classList.contains('dark');
    if (wantDark === currently) return;
    var thumb = document.getElementById('tthumb');
    var lbl   = document.getElementById('tlabel');
    if (wantDark) {
      svg.classList.add('dark'); isDark = true;
      if (thumb) thumb.setAttribute('cx', '52');
      if (lbl)   lbl.textContent = 'Light';
    } else {
      svg.classList.remove('dark'); isDark = false;
      if (thumb) thumb.setAttribute('cx', '16');
      if (lbl)   lbl.textContent = 'Dark';
    }
  }

  /* Portal API */
  window.setMode = setMode;
  window.addEventListener('message', function(e) {
    if (e.data && e.data.type === 'setMode') setMode(e.data.dark);
  });

})();
//
